UPDATE public.garden_import_queue SET payload = '{"species": "Ginger", "species_slug": "ginger", "varieties": [{"name": "Common Ginger (Queensland Ginger)", "slug": "common-ginger-queensland-ginger", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southeast Asia; commercially grown in Queensland since 1800s", "traits": "Grows 60-100cm tall, glossy green leaves, buff-colored rhizomes with knobby fingers", "flesh_fruit": "", "yield_notes": "Good productivity in subtropical conditions (15-25 tonnes/hectare)", "growing_notes": "Excellent adaptation to Brisbane''s subtropical climate. Plant in spring (September-November) for harvest in late autumn/winter. Grows well in semi-shade with consistent moisture. Tolerates Brisbane''s summer heat and humidity. Dies back in cool months but regrows from rhizomes. Suitable for container growing on patios.", "availability": "Widely available from Queensland nurseries, Daley''s Fruit, Bambooland, local garden centers", "sort_order": 0}, {"name": "Chinese Ginger (Canton Ginger)", "slug": "chinese-ginger-canton-ginger", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southern China (Shandong, Fujian provinces); 1800s introduction to Australia", "traits": "Large rhizomes, yellowish-colored, succulent texture, smooth thin skin", "flesh_fruit": "", "yield_notes": "High productivity (20-30 tonnes/hectare)", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Baby Ginger (Young Ginger)", "slug": "baby-ginger-young-ginger", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Early harvest of common ginger varieties; traditional Asian cultivation method", "traits": "Harvested at 4-5 months (immature stage), pale pink/yellow skin, tender shoots often attached", "flesh_fruit": "", "yield_notes": "Lower yield per plant but faster turnover (0.5-1kg per plant)", "growing_notes": "Perfect for Brisbane''s growing season. Plant in spring for summer/early autumn harvest before winter. Excellent for pickling, stir-fries, and fresh use. Stores for shorter periods (3-4 months max). Ideal for continuous cropping systems. Less fibrous makes it easier to prepare and digest.", "availability": "Seasonal availability at farmers markets, Asian grocers; grow from any ginger variety harvested early", "sort_order": 2}, {"name": "Native Ginger (Alpinia caerulea) 🌱", "slug": "native-ginger-alpinia-caerulea", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Indigenous to Queensland and northern NSW rainforests; 50,000+ years of traditional use", "traits": "Grows 1-2m tall, glossy sword-shaped leaves, white fragrant flowers, bright blue berries", "flesh_fruit": "", "yield_notes": "Moderate yield of edible shoots and abundant berry production", "growing_notes": "INDIGENOUS AUSTRALIAN SPECIES. Perfectly adapted to Brisbane''s subtropical climate. Grows naturally in Queensland''s coastal rainforests. Excellent for erosion control and bush tucker gardens. Tolerates full sun to full shade. Very hardy once established. Dies back in cool climates but evergreen in Brisbane. Cultural significance to Indigenous Australians. Used traditionally for medicinal and culinary purposes.", "availability": "The Seed Collection, Australian Plants Online, native plant nurseries throughout Queensland", "sort_order": 3}, {"name": "Rio de Janeiro", "slug": "rio-de-janeiro", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Brazil (introduced variety); widely adopted in tropical/subtropical regions since 1900s", "traits": "Bold, large rhizomes with prominent fingers, buff-colored skin", "flesh_fruit": "", "yield_notes": "Very high yielding (25-35 tonnes/hectare)", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Yellow Ginger (Hedychium flavescens)", "slug": "yellow-ginger-hedychium-flavescens", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Himalayas, Northern Vietnam, Sichuan; naturalized in Australia", "traits": "Short stem with tufted leaves, short thick rhizomes, ornamental yellow flowers", "flesh_fruit": "", "yield_notes": "Moderate rhizome production, valued more for flowers than roots", "growing_notes": "Adapts well to Brisbane''s subtropical environment. Primarily grown as ornamental but has medicinal applications. Used as analgesic for muscle pain, anti-inflammatory, antimicrobial properties. Prefers partial shade and consistent moisture. Flowers attract pollinators. Can become invasive in ideal conditions - plant responsibly.", "availability": "Bambooland, ornamental ginger specialists, subtropical plant nurseries", "sort_order": 5}, {"name": "Blue Hawaiian Ginger", "slug": "blue-hawaiian-ginger", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Brazil (native); cultivated in Hawaii and other subtropical regions", "traits": "Grows up to 3 feet tall, shiny green leaves, distinctive blue/purple hues in mature rhizomes", "flesh_fruit": "", "yield_notes": "Moderate yield, ornamental and culinary value", "growing_notes": "Suitable for Brisbane''s subtropical climate with temperature range 15-27°C ideal. Cannot tolerate direct sun - burns easily, requires shade or dappled light. Rich in iron, sodium, vitamins A and C. Antioxidant and anti-inflammatory properties. Requires regular fertilization. Good for containers or shaded garden beds. Blue coloration indicates high enzyme content (Zingibain).", "availability": "Specialty ginger nurseries, online tropical plant suppliers, limited availability in Australia", "sort_order": 6}, {"name": "Spring Ginger (Early Harvest)", "slug": "spring-ginger-early-harvest", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Early harvest stage of mature ginger varieties; traditional Asian practice", "traits": "Hand-like shape similar to mature ginger, plump and juicy with pink blush", "flesh_fruit": "", "yield_notes": "Medium yield at 5-6 month harvest", "growing_notes": "Perfect timing for Brisbane''s growing season - plant September, harvest February-March. Used in recipes with strong odors to neutralize unpleasant tastes. Excellent for fresh use. More tender than mature ginger but more developed than baby ginger. Good bridge crop between baby and mature ginger. Requires consistent watering during Brisbane''s hot summer.", "availability": "Harvest timing of standard ginger varieties; available at Asian markets seasonally", "sort_order": 7}, {"name": "Shampoo Ginger (Zingiber zerumbet)", "slug": "shampoo-ginger-zingiber-zerumbet", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to India, Southeast Asia; cultivated in Hawaii and Pacific Islands for millennia", "traits": "Grows 1-2m tall, pine cone-shaped flower heads release sudsy fluid when squeezed, red/orange bracts", "flesh_fruit": "", "yield_notes": "Good rhizome production, abundant flower production", "growing_notes": "Thrives in Brisbane''s subtropical climate below 1500ft elevation. Bitter ginger root provides quick relief for indigestion and upset stomach. Traditionally used as natural shampoo, conditioner, and skin lotion. Spreads via shallow rhizomes to form dense stands. Requires semi-shady spot and consistent moisture. Cultural significance in Pacific Island communities. Flowers attractive for ornamental purposes.", "availability": "Tropical plant specialists, Hawaiian plant suppliers, can be propagated from wild rhizomes where naturalized", "sort_order": 8}, {"name": "White Ginger (Hedychium coronarium)", "slug": "white-ginger-hedychium-coronarium", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to India, China, Southeast Asia; naturalized in Queensland", "traits": "Large herbaceous plant 1-3m tall, showy white fragrant flowers, spreads via rhizomes", "flesh_fruit": "", "yield_notes": "Prolific growth, forms extensive thickets under favorable conditions", "growing_notes": "CAUTION: Potentially invasive in Brisbane''s subtropical climate. Forms dense mats of rhizomes near soil surface. Has naturalized and become environmental weed in wetter areas of SE Queensland. Can suppress native plant regeneration. Prefers moist habitats. If planting, use containers or monitor closely. Beautiful ornamental but aggressive spreader. Listed on environmental weed lists in some regions.", "availability": "Available but not recommended for open garden planting due to invasive nature; better for containers", "sort_order": 9}, {"name": "Torch Ginger (Etlingera elatior)", "slug": "torch-ginger-etlingera-elatior", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Southeast Asia (Malaysia, Indonesia, Thailand)", "traits": "Tall plant 3-4m, spectacular red/pink flower spikes up to 1m tall, ornamental value", "flesh_fruit": "", "yield_notes": "Good flower production in warm climates", "growing_notes": "Can grow in Brisbane''s subtropical climate with frost protection. Needs warm position, partial shade. Usually deciduous in winter in Brisbane. Whole plant is edible - fruits, seed pods, seeds, flower stems used in traditional Indonesian and Thai dishes. Requires space due to large size. Best in protected garden areas.", "availability": "Bambooland, tropical ginger specialists, requires special order", "sort_order": 10}, {"name": "Shell Ginger (Alpinia zerumbet)", "slug": "shell-ginger-alpinia-zerumbet", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Eastern Asia (Japan, Taiwan, China)", "traits": "Ovate leaves with green stripes, grows 2-3m tall, clusters of pink buds, shell-like flowers", "flesh_fruit": "", "yield_notes": "Moderate leaf and rhizome production", "growing_notes": "", "availability": "", "sort_order": 11}, {"name": "Red Ginger (Alpinia purpurata)", "slug": "red-ginger-alpinia-purpurata", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Southeast Asia, Pacific Islands", "traits": "Striking red bracts, ornamental flowers, grows 2-3m tall", "flesh_fruit": "", "yield_notes": "Excellent for cut flowers, long-lasting", "growing_notes": "Thrives in Brisbane''s tropical and subtropical climate. Grown primarily for aesthetic appeal. Requires partial shade and consistent moisture. Can tolerate Brisbane''s summer heat with adequate water. Good for tropical garden designs. Makes excellent cut flower with long vase life. Provides year-round greenery in Brisbane.", "availability": "Bambooland, tropical plant nurseries throughout Queensland", "sort_order": 12}, {"name": "Pink Ginger (Alpinia zerumbet ''Variegata'')", "slug": "pink-ginger-alpinia-zerumbet-variegata", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Cultivar of Shell Ginger, Eastern Asia", "traits": "Beautiful pink flowers, variegated leaves with cream and green stripes", "flesh_fruit": "", "yield_notes": "Ornamental value, some culinary use of leaves", "growing_notes": "Excellent ornamental for Brisbane gardens. Grows well in subtropical conditions. Prefers dappled shade to full shade. Variegated foliage adds year-round interest. Can be grown in large containers. Frost sensitive - protect during occasional Brisbane cold snaps. Beautiful contrast plant for tropical-style gardens.", "availability": "Specialty ornamental nurseries, Bambooland, tropical plant specialists", "sort_order": 13}, {"name": "Beehive Ginger (Zingiber spectabile)", "slug": "beehive-ginger-zingiber-spectabile", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Southeast Asia (Malaysia, Thailand)", "traits": "Unique beehive-shaped inflorescence, yellow to red coloration as matures", "flesh_fruit": "", "yield_notes": "Good flower production, ornamental value", "growing_notes": "Can grow in Brisbane with warm position and frost protection. Prefers tropical conditions but adapts to subtropical. Avoid full sun as it can burn. Grows best in humid climate. All parts have strong gingery fragrance. Used in making appetizers in Asian cuisines. Attractive addition to tropical gardens. May be deciduous in Brisbane winters.", "availability": "Tropical ginger specialists, limited availability, special order", "sort_order": 14}, {"name": "Mango Ginger (Curcuma amada)", "slug": "mango-ginger-curcuma-amada", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to India, closely related to turmeric", "traits": "Ginger-like rhizomes with distinctive raw mango aroma", "flesh_fruit": "", "yield_notes": "Good rhizome production", "growing_notes": "Suitable for Brisbane''s subtropical climate. Growing requirements similar to common ginger. Used primarily in Indian cooking for pickles, chutneys, and soups. Can be grown in containers in cold climates during warm months. Requires rich, well-drained soil and partial shade. Interesting alternative to standard ginger with unique mango flavor.", "availability": "Indian spice plant nurseries, specialty suppliers, limited availability in Australia", "sort_order": 15}, {"name": "Greater Galangal (Alpinia galanga)", "slug": "greater-galangal-alpinia-galanga", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Indonesia and Southwest China, Thai Ginger", "traits": "Large plant up to 1.8m tall, reddish-brown knobbly rhizomes, greenish-white flowers", "flesh_fruit": "", "yield_notes": "Good productivity, harvested at 10-12 months", "growing_notes": "Adapts to Brisbane''s subtropical climate with proper care. Staple in Southeast Asian cuisine, essential for Thai curries. Harder and denser than ginger - best grated rather than chopped. Thrives in warm humid conditions. Grows well in USDA zones 8-11, suitable for Brisbane. Requires partial shade and consistent moisture. Medicinal uses in traditional Asian medicine.", "availability": "Asian plant nurseries, Baker Creek Heirloom Seeds, specialty suppliers, can propagate from store-bought rhizomes", "sort_order": 16}, {"name": "Lesser Galangal (Alpinia officinarum)", "slug": "lesser-galangal-alpinia-officinarum", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to China and Southeast Asia", "traits": "Smaller stature than greater galangal (90cm tall), reddish-brown rhizomes", "flesh_fruit": "", "yield_notes": "Moderate yield, slower growing (best harvested after 2 years)", "growing_notes": "Can grow in Brisbane but slower growing than greater galangal. Used extensively in traditional Chinese medicine. Historical use in European medieval cooking. Requires partial shade and well-drained soil. More cold-tolerant than greater galangal. Good for medicinal herb gardens. Less common in culinary use but valued for health properties.", "availability": "Specialty medicinal herb nurseries, Chinese herb suppliers, limited availability", "sort_order": 17}, {"name": "Myoga Ginger (Zingiber mioga)", "slug": "myoga-ginger-zingiber-mioga", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Native to Japan and East Asia", "traits": "Flowers and young shoots emerge from soil, perennial with spreading rhizomes", "flesh_fruit": "", "yield_notes": "Good production of flower buds and shoots", "growing_notes": "Suitable for Brisbane''s climate with adequate shade. Prefers partial shade and moist soil. In Brisbane, grow in shaded areas with consistent moisture. Unique ginger that''s harvested for flowers rather than roots. Prized in Japanese cuisine as a garnish. Can spread to form colonies. More cold-tolerant than tropical gingers. Good for understory planting.", "availability": "Japanese plant specialists, rare plant nurseries, limited availability in Australia", "sort_order": 18}, {"name": "Cochin Ginger 🏆", "slug": "cochin-ging