UPDATE public.garden_import_queue SET payload = '{"species": "Grapes", "species_slug": "grapes", "varieties": [{"name": "Carlos", "slug": "carlos", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "North Carolina State University, 1970", "traits": "Bronze-skinned, small berries (15-20mm), self-fertile, perfect flowers, vigorous vine", "flesh_fruit": "Sweet, juicy with distinctive fruity flavor, less musky than traditional muscadines", "yield_notes": "High yielding, 4-8 tons per acre, uniform ripening", "growing_notes": "Excellent subtropical adaptation. Self-fertile eliminates need for pollinizer. Intermediate tolerance to bitter rot, powdery mildew, angular leaf spot. Susceptible to black rot and Pierce''s disease in high pressure areas. Thrives in warm humid climates, performs exceptionally well in Brisbane conditions. Requires minimal spraying.", "availability": "Available from Australian nurseries including Daleys Fruit, subtropical specialist nurseries", "sort_order": 0}, {"name": "Noble", "slug": "noble", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "North Carolina State University, 1971", "traits": "Black-purple berries, medium size, excellent disease resistance, self-fertile", "flesh_fruit": "Rich, sweet, less musky flavor than typical muscadines, excellent for fresh eating", "yield_notes": "High yields, uniform berry ripening, consistent production", "growing_notes": "Most popular red muscadine for wine and juice. Self-fertile, excellent for Brisbane''s humid climate. High disease resistance to major fungal diseases. Flavor less musky than traditional muscadines making it excellent for fresh consumption. Ideal for coastal subtropical gardens. Performs well without intensive spray programs.", "availability": "Daleys Fruit Trees (exclusive Australian distributor), subtropical fruit nurseries", "sort_order": 1}, {"name": "Southern Home", "slug": "southern-home", "lineage_type": "hybrid", "climate_slug": "humi