UPDATE public.garden_import_queue SET payload = '{"species": "Henna", "species_slug": "henna", "varieties": [{"name": "STANDARD LAWSONIA INERMIS", "slug": "standard-lawsonia-inermis", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Tropical/subtropical Africa, Asia, Northern Australia", "traits": "Multi-branched shrub 2-6 meters, glossy dark green elliptical leaves 2-5cm long", "flesh_fruit": "", "yield_notes": "Lower than tropical regions; 200-500 kg/ha dry leaves (vs 1000-1500 in optimal zones)", "growing_notes": "Available from Australian native plant nurseries. Requires full sun, well-drained soil. In Brisbane, grow in large containers that can be moved to warmest microclimate in winter. Prune after leaves yellow in cooler months. Plant tolerates Brisbane''s humidity but produces less dye than in hotter climates.", "availability": "Daleys Fruit Trees (Queensland), Mudbrick Herb Cottage, All Rare Herbs, The Seed Vine (Australian nurseries)", "sort_order": 0}, {"name": "DESI TYPE", "slug": "desi-type", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "India (Rajasthan, Gujarat, Madhya Pradesh)", "traits": "Leafy canopy with larger green leaves, less thorny", "flesh_fruit": "", "yield_notes": "Better leaf yield potential; adapted to monsoon dry-wet cycles", "growing_notes": "Traditional Indian selection favored for commercial cultivation. In Brisbane, may struggle with consistent year-round moisture vs. the dry-wet cycles it evolved with. Best grown in controlled water regime - allow soil to dry between heavy waterings. Frost-tender; requires winter protection.", "availability": "Specialty seed suppliers; cuttings may be sourced from Indian plant importers (subject to quarantine regulations)", "sort_order": 1}, {"name": "MURALIYA TYPE", "slug": "muraliya-type", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "India (Rajasthan region)", "traits": "Woody canopy, small greyish-green leaves, hard pointed thorn-like branchlets", "flesh_fruit": "", "yield_notes": "Lower than Desi type; slower growing", "growing_notes": "More drought-tolerant and hardy than Desi type. The thorniness makes handling difficult. Not preferred for commercial cultivation but more resilient to stress. In Brisbane, this hardiness may be advantageous during dry periods. Better suited to hedging than dye production.", "availability": "Rare in Australian trade; primarily available in India", "sort_order": 2}, {"name": "CONTAINER-ADAPTED CULTIVARS", "slug": "container-adapted-cultivars", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selected for pot cultivation in temperate regions", "traits": "Compact growth 1-2 meters, suitable for moving indoors", "flesh_fruit": "", "yield_notes": "100-300g dry leaves per plant annually", "growing_notes": "RECOMMENDED FOR BRISBANE. These are standard L. inermis plants selected and maintained in containers. Best practice: Use 40-50cm pots with cactus/succulent mix. Move to warmest location (patio, greenhouse) during Brisbane''s coolest months (June-August). Water heavily then allow complete dry-down before next watering - replicate monsoon pattern. Brisbane''s humidity is beneficial; focus on maximizing summer heat exposure.", "availability": "Mudbrick Herb Cottage, Daleys Fruit Trees, The Seed Vine (sold as standard henna suitable for containers)", "sort_order": 3}, {"name": "STANDARD LAWSONIA INERMIS 🌱", "slug": "standard-lawsonia-inermis", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to tropical regions including India", "traits": "Multi-branched shrub 2-6 meters, dark green glossy leaves 2-5cm", "flesh_fruit": "", "yield_notes": "1000-1500 kg/ha dry leaves possible under rainfed conditions; 2000+ kg/ha with irrigation", "growing_notes": "HIGHLY RECOMMENDED FOR KERALA. Thrives in monsoon climate with hot, humid conditions. Plant during February-March, transplant after monsoon arrives (June-July). Grows as hedge or field crop. Known locally as \"Mailanchi\" (Malayalam). Used traditionally for body art (mehndi), hair conditioning, and cooling properties. Extremely well-adapted to Kerala''s climate - better than most Indian regions.", "availability": "Local Kerala nurseries, agricultural departments, traditional plant sellers", "sort_order": 0}, {"name": "DESI TYPE (INDIAN LANDRACE) 🏆🌱", "slug": "desi-type-indian-landrace", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Rajasthan, Gujarat, Madhya Pradesh - traditional Indian type", "traits": "Leafy canopy, larger green leaves, minimal thorns, vigorous growth", "flesh_fruit": "", "yield_notes": "High leaf yield potential 1500-2000 kg/ha in Kerala''s favorable climate", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "RAJASTHANI HENNA 🏆🌱", "slug": "rajasthani-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Rajasthan, India (Pali, Sojat regions) - ancient cultivation area", "traits": "Adapted to arid regions but grows vigorously in tropical monsoon", "flesh_fruit": "", "yield_notes": "Very high in monsoon climate - 1500-2500 kg/ha possible in Kerala", "growing_notes": "Rajasthan is India''s premier henna-producing region. While adapted to arid climate, this germplasm excels in Kerala''s monsoon conditions with adequate moisture. Higher quality dye than many other sources. Kerala''s temperature and humidity may produce even better yields than Rajasthan''s arid climate. Traditional source of premium mehndi. Historical cultivation exceeds 400+ years.", "availability": "Sojat nurseries (Rajasthan), agricultural seed suppliers, can be sourced through Indian agricultural networks", "sort_order": 2}, {"name": "SOJAT HENNA (GI TAGGED) 🏆🌱", "slug": "sojat-henna-gi-tagged", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Sojat City, Pali District, Rajasthan (Geographical Indication Tag #628/21)", "traits": "Fine texture leaves, rich green color, optimal lawsone content", "flesh_fruit": "", "yield_notes": "In Kerala climate: 2000-2500 kg/ha with proper management", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "PALI HENNA 🏆🌱", "slug": "pali-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Pali District, Rajasthan (22,000+ hectares under cultivation)", "traits": "Vigorous growth, good leaf production", "flesh_fruit": "", "yield_notes": "2000+ kg/ha potential in Kerala''s favorable growing conditions", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "GUJARAT HENNA 🏆🌱", "slug": "gujarat-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Gujarat State, India", "traits": "High lawsone content, good leaf size and production", "flesh_fruit": "", "yield_notes": "1500-2000 kg/ha in monsoon climates", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "MARWARI HENNA 🏆🌱", "slug": "marwari-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Marwar region, Rajasthan (historical name for Jodhpur area)", "traits": "Drought-hardy genetics, produces well even under stress", "flesh_fruit": "", "yield_notes": "1000-1800 kg/ha; drought tolerance may not be primary advantage in Kerala but hardiness is valuable", "growing_notes": "", "availability": "", "sort_order": 6}, {"name": "MADHYA PRADESH HENNA 🏆🌱", "slug": "madhya-pradesh-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Madhya Pradesh State, India", "traits": "Medium-sized shrub, good branching", "flesh_fruit": "", "yield_notes": "1200-1800 kg/ha", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "TAMIL NADU HENNA 🌱", "slug": "tamil-nadu-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Tamil Nadu, South India (neighboring state to Kerala)", "traits": "Adapted to South Indian tropical climate", "flesh_fruit": "", "yield_notes": "1500-2000 kg/ha in similar climate zones", "growing_notes": "EXCELLENT CHOICE FOR KERALA - Tamil Nadu shares similar climate characteristics with Kerala. Known locally as \"Maruthani\" (similar to Malayalam \"Maruthani\"). This South Indian selection is already adapted to high humidity, monsoon patterns, and tropical heat. Likely the best genetic match for Kerala conditions after local selections. Cultural significance in South Indian wedding traditions.", "availability": "Tamil Nadu nurseries, agricultural colleges, local plant sellers in South India", "sort_order": 8}, {"name": "KERALA LOCAL SELECTION 🌱", "slug": "kerala-local-selection", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Kerala State (backyard and traditional cultivation)", "traits": "Selected over time for Kerala climate; moderate growth 2-4 meters", "flesh_fruit": "", "yield_notes": "1000-1500 kg/ha", "growing_notes": "BEST ADAPTED TO KERALA - While not a commercial crop, henna has been grown in Kerala backyards for generations for personal mehndi use. These local selections are perfectly adapted to Kerala''s specific rainfall patterns, humidity, and temperature ranges. Look for plants in traditional home gardens, ayurvedic gardens, or from elder community members who maintain \"Mailanchi\" plants. Most reliable for Thiruvalla region.", "availability": "Local Kerala plant exchanges, traditional home gardens, ayurvedic plant nurseries, agricultural extension offices", "sort_order": 9}, {"name": "AFRICAN HENNA", "slug": "african-henna", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "North Africa (Egypt, Sudan, Morocco), East Africa (Somalia)", "traits": "Variable based on region; generally hardy and drought-tolerant", "flesh_fruit": "", "yield_notes": "1000-2000 kg/ha depending on specific origin", "growing_notes": "", "availability": "", "sort_order": 10}, {"name": "EGYPTIAN HENNA 🏆🌱", "slug": "egyptian-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Egypt (Nile Valley, traditional cultivation areas)", "traits": "Classical Egyptian type, historically significant", "flesh_fruit": "", "yield_notes": "1000-1800 kg/ha", "growing_notes": "Egyptian henna has oldest documented use (3400 BCE - over 5000 years). Extreme historical and cultural significance. While adapted to Nile''s dry climate with seasonal flooding, this pattern somewhat similar to monsoon cycles. Kerala''s year-round warmth advantageous. Ancient heirloom with unmatched historical pedigree. Traditional Egyptian privet designation.", "availability": "Specialty suppliers, botanical gardens, international seed sources (import permits required)", "sort_order": 11}, {"name": "PAKISTANI/PUNJAB HENNA 🏆🌱", "slug": "pakistani-punjab-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Pakistan, Punjab region (shared with Indian Punjab)", "traits": "Vigorous growth in subtropical monsoon climate", "flesh_fruit": "", "yield_notes": "1500-2000 kg/ha in monsoon climates", "growing_notes": "", "availability": "", "sort_order": 12}, {"name": "YEMENI HENNA", "slug": "yemeni-henna", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Yemen, Arabian Peninsula", "traits": "Adapted to hot, arid conditions with some moisture", "flesh_fruit": "", "yield_notes": "Moderate 800-1500 kg/ha; may increase in Kerala''s moisture", "growing_notes": "Yemen has ancient henna traditions, particularly for wedding ceremonies. Flowers especially fragrant and used in traditional perfumery. While from arid region, may adapt to Kerala warmth. Ancient cultivation (1000+ years). Cultural significance in Arabian/Islamic traditions.", "availability": "Specialty Middle Eastern seed suppliers (import regulations apply)", "sort_order": 13}, {"name": "BANGLADESHI HENNA 🌱", "slug": "bangladeshi-henna", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Bangladesh", "traits": "Adapted to monsoon tropical climate very similar to Kerala", "flesh_fruit": "", "yield_notes": "1200-1800 kg/ha", "growing_notes": "", "availability": "", "sort_order": 14}], "variety_count": 19}'::jsonb,
