UPDATE public.garden_import_queue SET payload = '{"species": "Jaboticaba", "species_slug": "jaboticaba", "varieties": [{"name": "Sabara", "slug": "sabara", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Minas Gerais & Rio de Janeiro regions, Brazil. Pre-1900s heirloom.", "traits": "Medium-sized tree 4-8m, compact growth. Small to medium fruits 2-3cm, thin dark purple to black skin. Coppery new growth, glossy dark green mature leaves.", "flesh_fruit": "Sweet white gelatinous pulp, grape-like texture with tropical flavor notes. Slightly spicy piney skin. 1-3 seeds.", "yield_notes": "Very productive. 3-4 crops per year once mature. Precocious bearing.", "growing_notes": "", "availability": "", "sort_order": 0}, {"name": "Paulista", "slug": "paulista", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "São Paulo state, Brazil. Traditional variety, introduced to California 1904, survived until 1917.", "traits": "Larger tree 8-12m, vigorous growth. Very large fruits 3-4cm, thick leathery skin. Large lanceolate leaves.", "flesh_fruit": "Sweet pulp, slightly tougher skin than Sabara. White to rose-tinted flesh. 1-4 larger seeds.", "yield_notes": "Heavy producer. Typically 1-2 major crops per year. Late season.", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Red Hybrid (Precocious)", "slug": "red-hybrid-precocious", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Brazil hybrid (P. cauliflora x P. aureana). Modern selection for early fruiting.", "traits": "Dwarf compact tree 2.5-3m, ideal for containers. Greenish-red to scarlet fruits 2-2.5cm. Dwarfing habit, multi-trunk growth.", "flesh_fruit": "Very sweet, easily peeled thin skin. Balanced sweet-tart flavor profile, similar to blueberry yogurt. Small seeds.", "yield_notes": "Extremely prolific. 5-7 crops per year in optimal conditions. Back-to-back blooming.", "growing_notes": "", "availability": "", "sort_order": 2}, {"na