eage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Imported to Australia, grafted material. Documented in 1980s Australian trials.", "traits": "Grafted variety available in Australian collections.", "flesh_fruit": "Standard black jaboticaba quality.", "yield_notes": "Grafted trees fruit earlier than seedlings.", "growing_notes": "", "availability": "Limited Australian collector availability.", "sort_order": 17}, {"name": "Z4 Hybrid", "slug": "z4-hybrid", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Modern hybrid selection. Fast-bearing variety.", "traits": "Fruits directly on trunk. Hybrid vigor. Compact 3-5m growth.", "flesh_fruit": "Very sweet flavor, thin skin. Excellent eating quality.", "yield_notes": "Fruits frequently throughout year. Productive 3-5 years from planting.", "growing_notes": "", "availability": "", "sort_order": 18}, {"name": "Blue (Myrciaria vexator)", "slug": "blue-myrciaria-vexator", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Costa Rica, Panama, Venezuela. Also called False Jaboticaba or Blue Grape.", "traits": "Slow-growing evergreen to 10m. Multiple trunks, peeling bark reveals lighter interior. Lance-shaped glossy green leaves. White snowy flowers with prominent stamen.", "flesh_fruit": "Bluish-purple edible fruits 2.5-3.8cm, grape-like with fruity aroma. Sweet pulp, pit like grape.", "yield_notes": "Greater drought tolerance than true jaboticaba once established.", "growing_notes": "", "availability": "Limited specialty sources Australia.", "sort_order": 19}, {"name": "Escarlate (Scarlet)", "slug": "escarlate-scarlet", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Brazil, Red Hybrid type. Selected for vivid color.", "traits": "Small compact tree, excellent for containers. Vivid red-scarlet fruits 2-2.5cm. Wide short leaves 6-7cm x 5cm with printed ribs.", "flesh_fruit": "Very sweet, juicy. Superior color, flavor, an