UPDATE public.garden_import_queue SET payload = '{"species": "Jackfruit", "species_slug": "jackfruit", "varieties": [{"name": "Black Gold", "slug": "black-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia (selected cultivar)", "traits": "Medium-sized fruit averaging 6-7kg. Dark green skin with sharp fleshy spines that do not flatten at maturity. Vigorous tree with dense, manageable canopy.", "flesh_fruit": "Deep orange flesh, soft texture. Sweet flavor with pleasant aroma. 35% edible flesh percentage.", "yield_notes": "Heavy producer, 55-90kg per tree annually with pruning", "growing_notes": "Excellent subtropical performance. Can be maintained at 2-2.5m height. Tolerates Brisbane''s occasional cool weather. Popular in Queensland nurseries. Used as rootstock.", "availability": "Daleys Fruit Tree Nursery, Queensland nurseries, widely available Brisbane region", "sort_order": 0}, {"name": "Golden Nugget", "slug": "golden-nugget", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia (selected cultivar)", "traits": "Round, small to medium fruit, yellow skin, averaging 3kg. Fast-growing tree with distinctive dark green, rounded leaves.", "flesh_fruit": "Dark orange flesh with medium firmness. Excellent flavor, butter-soft when fully ripe. No fiber.", "yield_notes": "60-80kg per tree per year, consistent producer", "growing_notes": "Adapts well to subtropical Brisbane climate. May split during heavy rains. Good humidity tolerance. Popular with Australian growers.", "availability": "Queensland fruit tree nurseries, Brisbane suppliers", "sort_order": 1}, {"name": "Honey Gold", "slug": "honey-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Thailand/Malaysia, adapted to Australia", "traits": "Small to medium fruit, 2-3kg. Golden-yellow skin. Dwarf cultivar, compact tree.", "flesh_fruit": "Golden flesh with honey-like sweetness. Peachy interior, soft texture. Exceptionally sweet.", "yield_notes": "Moderate, early bearing within 2-3 years", "growing_notes": "Excellent for Brisbane''s subtropical conditions. Small size ideal for home gardens. Heat and humidity tolerant. Dwarf growth habit reduces space requirements.", "availability": "Specialty fruit nurseries Queensland, Brisbane area", "sort_order": 2}, {"name": "Lemon Gold", "slug": "lemon-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia (block-shaped variety)", "traits": "Unique block/square shape, 12-13kg fruit. Yellow skin at maturity.", "flesh_fruit": "Firm, crisp texture. Extraordinarily sweet flavor.", "yield_notes": "Good productivity", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Brinsmead Special", "slug": "brinsmead-special", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Kyogle, Northern NSW/QLD border region. Selected by Bob Brinsmead at Tropical Fruit World", "traits": "Latex-free variety (major advantage). Crisp orange flesh. Chance seedling selection.", "flesh_fruit": "Orange crisp flesh, easy to prepare due to latex-free properties.", "yield_notes": "Crops well in subtropics", "growing_notes": "Outstanding subtropical adaptation. Grows well in Brisbane climate zone. Latex-free makes processing much easier. Best selection from Tropical Fruit World.", "availability": "Daleys Fruit Tree Nursery", "sort_order": 4}, {"name": "Cosmic Gold", "slug": "cosmic-gold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland selection", "traits": "Sweet variety with grafted reliability.", "flesh_fruit": "Yellow/gold flesh with vanilla, banana and mango flavors.", "yield_notes": "Good production", "growing_notes": "Brisbane-suitable. Sweet complex flavor profile. Available as grafted trees which fruit earlier.", "availability": "Edibles Only Nursery Inala Brisbane, Queensland nurseries", "sort_order": 5}, {"name": "Sunshine Crunch / Ratu Red", "slug": "sunshine-crunch-ratu-red", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "New Queensland selection", "traits": "Very large fruit variety. Crunchy texture type.", "flesh_fruit": "Gold to pink/red flesh depending on ripeness. Crunchy texture.", "yield_notes": "Large individual fruits", "growing_notes": "Adapted to Queensland conditions. Novel flesh color. Good subtropical performance.", "availability": "Brisbane nurseries, grafted selections", "sort_order": 6}, {"name": "Galaxy", "slug": "galaxy", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland selection", "traits": "Crunchy variety, grafted for consistency.", "flesh_fruit": "Superior flavor, crunchy texture. Good for both curries and fresh eating.", "yield_notes": "Productive, fruits in 1-2 years from grafted", "growing_notes": "Sun-hardened for Queensland conditions. Handles subtropical weather well. Versatile use.", "availability": "Fruitopia Nursery Queensland", "sort_order": 7}, {"name": "Rajang", "slug": "rajang", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Ingham, North Queensland (new clonal selection)", "traits": "Orange crisp flesh type. Larger fruit, later maturing than Amber.", "flesh_fruit": "Orange, crisp texture. Good quality.", "yield_notes": "Productive clonal variety", "growing_notes": "Bred for Australian tropical/subtropical conditions. Performs well in Queensland. Heat and humidity tolerant. Commands higher market prices.", "availability": "Specialist nurseries North Queensland", "sort_order": 8}, {"name": "Amber", "slug": "amber", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Ingham, North Queensland (new clonal selection)", "traits": "Orange crisp flesh type. Earlier maturing than Rajang.", "flesh_fruit": "Orange, crisp texture.", "yield_notes": "Good productivity", "growing_notes": "Australian-bred for subtropical conditions. Earlier fruiting advantage. Well-adapted to Brisbane region.", "availability": "Specialist nurseries North Queensland", "sort_order": 9}, {"name": "Fitzroy Selection", "slug": "fitzroy-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Fitzroy Nursery, Rockhampton Queensland", "traits": "Large fruit. Selected for quality.", "flesh_fruit": "Yellow crisp flesh with excellent flavor. 99% excellent rating at Rockhampton Horticultural display.", "yield_notes": "Good production", "growing_notes": "Selected specifically for Central Queensland conditions. Highly rated for flavor. Subtropical adapted.", "availability": "Daleys Fruit Tree Nursery, Queensland", "sort_order": 10}, {"name": "Kyogle Selection (Soft Type)", "slug": "kyogle-selection-soft-type", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Kyogle, Northern NSW (subtropical border region)", "traits": "Choice seedling selection. Soft aril type.", "flesh_fruit": "Soft arils perfect for drying or freezing. Superior flavor. Rich texture without stringy fibers.", "yield_notes": "Good fruiting in subtropics", "growing_notes": "Proven subtropical performance. Selected from area with similar climate to Brisbane. Easy to preserve.", "availability": "Daleys Fruit Tree Nursery", "sort_order": 11}, {"name": "Daleys Favourite", "slug": "daleys-favourite", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Daleys Nursery selection, Queensland", "traits": "Small sized fruit, about 2kg, packed with arils.", "flesh_fruit": "Soft flesh, rich and delicious. Hints of banana, pineapple and tropical flavors. No stringy fibers.", "yield_notes": "High aril to fruit ratio", "growing_notes": "Selected as nursery favorite for Queensland. Manageable fruit size. Excellent eating quality. Subtropical performer.", "availability": "Daleys Fruit Tree Nursery Kyogle", "sort_order": 12}, {"name": "Meadowcroft Farm Selection", "slug": "meadowcroft-farm-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Meadowcroft Farm, Queensland (seedling trial selection)", "traits": "Selected from multiple trees grown in same conditions.", "flesh_fruit": "Orange crunchy flesh in abundance. Little latex. Tropical flavors like pineapple and mango. Even rags are edible.", "yield_notes": "High productivity, 300+ grafted trees", "growing_notes": "Field tested in Queensland conditions. Low latex advantage. Described as addictive. December fruiting season. Supplies southern markets.", "availability": "Meadowcroft Farm QLD", "sort_order": 13}, {"name": "Northern NSW Vigorous Selection", "slug": "northern-nsw-vigorous-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Northern NSW (subtropical region)", "traits": "Vigorous selection with dense, highly manageable canopy.", "flesh_fruit": "Deep orange aril flesh, soft. Strong, sweet flavor and aroma.", "yield_notes": "Average 6kg fruit. High productivity.", "growing_notes": "Frost-free subtropical locations. Can be pruned compact. Consistent cropper. Similar climate to Brisbane.", "availability": "Specialist nurseries Northern NSW/QLD border", "sort_order": 14}, {"name": "Vietnam Super Early", "slug": "vietnam-super-early", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Vietnam, adapted to Australia", "traits": "Remarkably fast-bearing, produces fruit in just over 1 year. Dwarf variety, doesn''t grow too large.", "flesh_fruit": "Good quality fruit.", "yield_notes": "Early bearing major advantage", "growing_notes": "Excellent for Brisbane''s subtropical climate. Small size makes fruit picking easy. Cold-hardy for a tropical fruit. Manageable tree size for home gardens.", "availability": "Queensland nurseries, specialty suppliers", "sort_order": 15}, {"name": "Cochin", "slug": "cochin", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia (selected from Indian Kerala region genetics)", "traits": "Low vigor tree, sparse upright narrow canopy. Heritage variety characteristics.", "flesh_fruit": "Soft and juicy bulbs. Aromatic ripe fruit.", "yield_notes": "Moderate", "growing_notes": "", "availability": "", "sort_order": 16}, {"name": "Dang Rasimi", "slug": "dang-rasimi", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Thailand, widely adapted", "traits": "Bright green to pale yellow fruit, 8kg average. Sharp spines that don''t flatten. Uniform shape when thinned. Very vigorous, requires annual pruning.", "flesh_fruit": "Deep orange, firm flesh. Mild sweet flavor, pleasant aroma. 32% edible percentage.", "yield_notes": "Very high, 75-125kg per tree", "growing_notes": "Can be maintained at 3-3.5m with pruning. Excellent subtropical adaptation. Popular internationally. Good humidity tolerance.", "availability": "Specialty fruit tree nurseries Queensland", "sort_order": 17}, {"name": "J-31", "slug": "j-31", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia (selected cultivar)", "traits": "Large irregular fruit with prominent blunt spines, 12kg. Moderately vigorous, spreading canopy.", "flesh_fruit": "Deep yellow, firm flesh with thick walls. Sweet rich flavor, strong earthy aroma. 36% edible.", "yield_notes": "42-60kg per year at 2-2.5m size. Off-season fruiting capability.", "growing_notes": "Cold resistance advantage. Sweet rich flavor. Adapts to subtropical Brisbane conditions. Can produce fall/winter fruit.", "availability": "Imported variety available through specialty nurseries", "sort_order": 18}, {"name": "NS1", "slug": "ns1", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Malaysia (one of first superior cultivars in Western Hemisphere)", "traits": "Dark green blocky fruit, 4.2kg. Blunt flattened spines that open at ripening. Dense upright canopy.", "flesh_fruit": "Dark orange, firm. Rich sweet flavor. 34% edible percentage.", "yield_notes": "Heavy production, 90kg+ per tree", "growing_notes": "Can be maintained at 2.5-3m with moderate pruning. Proven subtropical performer. Used as rootstock. Reliable producer in Brisbane region.", "availability": "Established variety, various Queensland nurseries", "sort_order": 19}, {"name": "Cheena", "slug": "cheena", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Natural hybrid (Jackfruit × Champedak)", "traits": "Long narrow uniform fruit, 2.4kg. Green skin with blunt spines that yellow at maturity. Open low spreading habit.", "flesh_fruit": "Deep orange, soft somewhat fibrous. Excellent flavor. Intense earthy aroma. 33% edible. Quick preparation (15 minutes vs 1-2 hours).", "yield_notes": "50-70kg per tree", "growing_notes": "Can be maintained at 2.5m. Easy processing major advantage. Subtropical adapted. Unique hybrid characteristics.", "availability": "Specialty nurseries Queensland", "sort_order": 20}, {"name": "Golden Pillow (Mong Tong)", "slug": "golden-pillow-mong-tong", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Thailand (introduced 1980s)", "traits": "Small highly manageable tree, 3m height and spread. Medium fruit 3.6-5.5kg. Little latex.", "flesh_fruit": "Thick crunchy golden flesh. Mild sweet flavor, no musky aftertaste. 35-40% edible. 65-75 seeds.", "yield_notes": "Precocious fruiting - bears in second year", "growing_notes": "Ideal for Brisbane gardens due to small size. Quick bearing. Low latex advantage. Reputation for beauty and quality in Thailand.", "availability": "Specialty importers, limited Queensland availability", "sort_order": 21}, {"name": "Ceylon / Singapore Jack 🌱", "slug": "ceylon-singapore-jack", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Sri Lanka, introduced to India 1949", "traits": "Remarkably early 