UPDATE public.garden_import_queue SET payload = '{"species": "Kiwi", "species_slug": "kiwi", "varieties": [{"name": "Vincent", "slug": "vincent", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "China, developed for subtropical climates", "traits": "Medium-sized fruit, egg-shaped, fuzzy brown skin, vigorous vine growth, excellent low-chill variety", "flesh_fruit": "Bright green flesh, sweet tropical flavor, medium size (80-100g), excellent eating quality", "yield_notes": "High productivity, produces large crops consistently", "growing_notes": "EXCELLENT FOR BRISBANE - Only 100-200 chill hours required. Thrives in warm subtropical climates. Tolerates high humidity. Pairs with Tomuri male pollinator. Well-suited to Brisbane''s mild winters and warm summers. Disease resistant.", "availability": "Available from Queensland and NSW nurseries, Daleys Fruit Tree Nursery", "sort_order": 0}, {"name": "Sweetie (Daleys Selection)", "slug": "sweetie-daleys-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia, selected by Daleys Nursery from golden kiwi seedling, 2000s", "traits": "Small to medium fruit, vigorous hardy growth, specifically bred for subtropical Queensland", "flesh_fruit": "Yellow-green flesh, sweet flavor, smooth texture", "yield_notes": "Good yields in subtropical conditions", "growing_notes": "EXCELLENT FOR BRISBANE - Very low chill requirement specifically selected for subtropics. Perfect for Brisbane gardens. Australian-bred for local conditions. Requires specific male pollinator also from Daleys.", "availability": "Daleys Fruit Tree Nursery, Kyogle NSW", "sort_order": 1}, {"name": "Hayward Seedling (Queensland Selection)", "slug": "hayward-seedling-queensland-selection", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Queensland, Australia, selected as Hayward seedling adapted to warmer climates, 1990s", "traits": "Similar to Hayward but slightly smaller, more elongated shape, adapted to warmer winters", "flesh_fruit": "Light-green flesh, good flavor, typical fuzzy brown skin", "yield_notes": "Productive in Queensland conditions", "growing_notes": "EXCELLENT FOR BRISBANE - Relatively low chill requirement compared to standard Hayward. Originated in Queensland, well-adapted to Brisbane climate. Handles humid subtropical conditions better than traditional Hayward.", "availability": "Queensland specialist nurseries, Daleys", "sort_order": 2}, {"name": "Elmwood", "slug": "elmwood", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "New Zealand, developed for low-chill regions", "traits": "Extremely vigorous growth, large showy fragrant blossoms, very large fruit (up to 280g/10 oz)", "flesh_fruit": "Green flesh, excellent flavor, extremely large kiwi-shaped fruits", "yield_notes": "Very high yields, bears fruit at young age (200-260 lbs per mature vine)", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Abbott", "slug": "abbott", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "New Zealand, early selection from Chinese germplasm, 1920s-1930s", "traits": "Early flowering and maturing, medium-sized round fruit, densely hairy brown skin", "flesh_fruit": "Light-green flesh, very sweet taste, lower ascorbic acid, medium titratable acidity", "yield_notes": "Good yields, productive", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Dexter", "slug": "dexter", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia/California, developed by Dr. David Dexter, 1970s", "traits": "Medium size, slightly elongated, quite hairy, compact growth habit", "flesh_fruit": "Green flesh, good flavor, sweet tropical taste", "yield_notes": "Good production, early ripening", "growing_notes": "", "availability": "", "sort_order": 5}, {"name": "Blake", "slug": "blake", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "New Zealand, HortResearch breeding program, 1990s", "traits": "Small to medium fruit, teardrop-shaped, early maturing (6-8 weeks before Hayward)", "flesh_fruit": "Golden-brown smooth skin, juicy sweet flesh, slightly more acidic than Hayward", "yield_notes": "Precocious variety, bears fruit one year earlier than other varieties, heavy yields", "growing_notes": "SUITABLE FOR BRISBANE - Low-chill requirement. Very early ripening perfect for areas with early autumn frosts. Partially self-fruitful. Vigorous disease-resistant vines. Good storage capacity. Flowers very early. Excellent for extending harvest season.", "availability": "Specialty nurseries, limited in Australia", "sort_order": 6}, {"name": "Allison", "slug": "allison", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "New Zealand, chance seedling discovered 1920s, named after Alexander Allison", "traits": "Medium-sized oblong fruit, densely hairy brownish skin, early maturing", "flesh_fruit": "Light-green flesh, good flavor, good balance of sweetness and acidity", "yield_notes": "Good yields, reliable producer", "growing_notes": "", "availability": "", "sort_order": 7}, {"name": "Bruno", "slug": "bruno", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "New Zealand, named after Bruno Just, early nurseryman, 1930s-1940s", "traits": "Large elongated cylindrical fruit, dark brown skin with short dense hairs", "flesh_fruit": "Light-green flesh, good flavor, higher ascorbic acid content than Abbott", "yield_notes": "Very vigorous, produces large crops", "growing_notes": "", "availability": "", "sort_order": 8}, {"name": "Saanichton 12", "slug": "saanichton-12", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Vancouver Island, British Columbia, Canada, developed for coastal climate, 1980s", "traits": "Medium-large fruit, vigorous growth, cold-hardy in mild climates", "flesh_fruit": "Sweet